var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서, 본인이 멋대로 계약을 맺었으니 회사더러 출격해 달라.","JPN":"それで、自分が勝手に契約を結んだから、会社に出撃してほしい。","ENG":"So you agreed to a deal on a whim and you want the company's support...","TWN":"所以，妳自己擅自簽了個契約，然後就要求公司出擊。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 말인가요?","JPN":"ということですか？","ENG":"Is that what you're saying?","TWN":"是這個意思嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그...... 여러 가지 복잡한 사정들이 있지만......","JPN":"その……いろいろと複雑な事情はあるけど……","ENG":"I mean... There's a lot of complex factors involved..","TWN":"這……雖然其中有很多複雜的情況……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"요약하면...... 맞아.","JPN":"まとめると……その通りだよ。","ENG":"But that's the gist of it... Yeah.","TWN":"但簡單來說……是這樣沒錯。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아.......","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"신입 교육에 소홀하다 싶었더니 결국 이런 문제가 터지는군요.","JPN":"新人研修が手薄だと思ってたら、案の定こんな問題が起こるなんて。","ENG":"I knew rookie training was too lax... Now it's come to bite me in the ass.","TWN":"我才說我們疏忽了對新人的教育，結果就搞出了這種問題。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이봐요, 미나 양.","JPN":"あのね、ミナさん。","ENG":"Look, Mina.","TWN":"喂，米娜小姐。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"입사하자마자 휴가 쓰고 놀러 다니는 거야, 잘 몰라서 그렇다고 할 수도 있습니다.","JPN":"入社してすぐに休暇を取って遊ぶのは、まだわかってないから仕方がありません。","ENG":"When you took leave as soon as you were hired, I thought you just didn't know any better.","TWN":"妳剛進公司，就馬上休假出去玩了，所以對這些事可能不太清楚吧。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 회사 이름을 멋대로 팔고 다녀요?","JPN":"けれど会社の名前をむやみに出すなんて。","ENG":"But how dare you use the company's name like it's your own?","TWN":"但妳怎麼可以一下就出賣了公司的名號呢？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사고를 쳐도 정도라는 게 있습니다.","JPN":"とんでもないことをしてくれたわね。","ENG":"You're at the limit of my good graces.","TWN":"即使要闖禍，也該有個限度。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"게다가 다른 상대도 아니고 CIA라니......","JPN":"しかも、他でもなく、CIAだなんて……","ENG":"And why does it have to be the CIA of all people...","TWN":"而且對象不是別人，偏偏是CIA……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미나 양은 아직 업계 경력이 짧아 잘 모르겠지만, 이 바닥에서 정보부 놈들이란 상종하면 신세 망치기 딱 좋은 재해, 역병, 파랑새 같은 겁니다.","JPN":"ミナさんはまだ業界歴が短いのでわかってないと思いますが、この業界で情報局員とは、遭遇すると身を滅ぼしてしまう災害や疫病神、青い鳥のようなものです。","ENG":"You might not know this since you're new, but working with spooks like that is career suicide in this line of work.","TWN":"米娜小姐的就業經歷比較淺，所以可能不太清楚。但是在這個圈子裡，如果和情報部的那些傢伙們打交道，就等於是碰到災難、瘟疫、烏鴉。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그놈들이랑 엮이면 대체 일이 얼마나 귀찮아지는지 알긴 아는 건가요?","JPN":"そいつらに絡まれたら、いったいどれだけ面倒なことになるかおわかりですか？","ENG":"Do you have any idea how troublesome it is to get involved with them?","TWN":"妳知道和那些傢伙牽扯在一起會有多麻煩嗎！？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 그게 이쪽도 나름대로 깊이 생각해서.......","JPN":"いや、それはこっちもそれなりに深く考えた結果……","ENG":"But they also put a lot of thought into this as well...","TWN":"不，這我也有自己深思熟慮過……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"ちょっといいかい。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"여기선 내가 얘기하는 게 빠르겠군.","JPN":"ここは私から話すのが早そうだ。","ENG":"I'd better take it from here.","TWN":"這裡讓我來說會比較快吧。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그쪽은 누구시죠?","JPN":"……どちら様でしょうか？","ENG":"...And who are you?","TWN":"……在那邊的是誰？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"댁네 사원에게 일을 부탁한 재해, 역병, 파랑새 같은 의뢰인이지.","JPN":"お宅の社員に仕事を頼んだ、災害、疫病神、青い鳥みたいな依頼人だよ。","ENG":"I'm that suicide-inducing spook that asked your employee for this favor.","TWN":"正是委託貴公司員工幫忙，如同災難、瘟疫、烏鴉般的委託人。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};